      "path": "pkg/registry/apps/deployment/storage/storage.go",
      "symbol": "NewREST",
      "description": "Creates a REST storage handler for Deployments on the API server. Sets up a genericregistry.Store with the deploymentStrategy for validation and creates the Storage object that will handle the Create request."
    },
    {
      "repo": "kubernetes/kubernetes",
      "path": "pkg/registry/apps/deployment/strategy.go",
      "symbol": "deploymentStrategy.Validate",
      "description": "Validates the Deployment object during the Create request. This strategy validates the Deployment spec, template, and other fields according to Kubernetes API rules before persistence."
    },
    {
      "repo": "kubernetes/kubernetes",
      "path": "staging/src/k8s.io/apiserver/pkg/registry/generic/registry/store.go",
      "symbol": "Store.Create",
      "description": "API server's generic storage handler that processes Create requests. Validates the object, generates metadata, calculates TTL, and calls e.Storage.Create() to persist the object to the storage backend (etcd)."
    },
    {
      "repo": "etcd-io/etcd",
      "path": "server/etcdserver/api/v3rpc/key.go",
      "symbol": "kvServer.Put",
      "description": "gRPC handler for the Put request in etcd. Validates the PutRequest and delegates to s.kv.Put() to process the write request through the Raft consensus protocol."
    },
